-- [ ObfusPro+ ]
local xhYzr = bit32 or bit or error("ObfusPro+: Environment error");
local function wZrYPF(izCeD)
    local rCPgkFom = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    local YiTQR = string.gsub(izCeD, '[^' .. rCPgkFom .. ']', '')
    local XNDhwqt = {}
    for Hhxv = 1, #YiTQR, 4 do
        local xpK, DlT, BdZ, qQv = string.byte(YiTQR, Hhxv, Hhxv + 3)
        if not xpK then break end
        local Glfl = string.find(rCPgkFom, string.char(xpK)) - 1
        local KOlI = string.find(rCPgkFom, string.char(DlT)) - 1
        local KcvG = BdZ and string.find(rCPgkFom, string.char(BdZ)) - 1 or 0
        local tkzv = qQv and string.find(rCPgkFom, string.char(qQv)) - 1 or 0
        local UfZy = Glfl * 262144 + KOlI * 4096 + KcvG * 64 + tkzv
        local iFfJ = xhYzr.band(xhYzr.rshift(UfZy, 16), 255)
        table.insert(XNDhwqt, string.char(xhYzr.bxor(iFfJ, 95)))
        if BdZ and string.char(BdZ) ~= '=' then
            iFfJ = xhYzr.band(xhYzr.rshift(UfZy, 8), 255)
            table.insert(XNDhwqt, string.char(xhYzr.bxor(iFfJ, 95)))
        end
        if qQv and string.char(qQv) ~= '=' then
            iFfJ = xhYzr.band(UfZy, 255)
            table.insert(XNDhwqt, string.char(xhYzr.bxor(iFfJ, 95)))
        end
    end
    return table.concat(XNDhwqt)
end
